 This program constructs an operator against the in-memory service (no credentials needed), writes data, reads it back, and inspects its metadata.  #include &quot;opendal.hpp&quot; #include &lt;iostream&gt; #include &lt;string&gt; int main() { // Construct an operator for the &quot;memory&quot; service (no credentials needed). opendal::Operator op(&quot;memory&quot;); // Write a string. op.Write(&quot;hello.txt&quot;, &quot;Hello, OpenDAL!&quot;); // Read it back. std::string data = op.Read(&quot;hello.txt&quot;); std::cout &lt;&lt; data &lt;&lt; &quot;
&quot;; // Hello, OpenDAL! // Inspect metadata. opendal::Metadata meta = op.Stat(&quot;hello.txt&quot;); std::cout &lt;&lt; &quot;size=&quot; &lt;&lt; meta.ContentLength() &lt;&lt; &quot;
&quot;; std::cout &lt;&lt; &quot;is_file=&quot; &lt;&lt; meta.IsFile() &lt;&lt; &quot;
&quot;; // Remove. op.Remove(&quot;hello.txt&quot;); std::cout &lt;&lt; &quot;exists=&quot; &lt;&lt; op.Exists(&quot;hello.txt&quot;) &lt;&lt; &quot;
&quot;; // 0 return 0; }   Compile and run (assuming the binding has been installed into your build tree):  clang++ -std=c++17 -I/path/to/opendal/bindings/cpp/include \ -L/path/to/build -lopendal_cpp \ hello.cpp -o hello ./hello

 The example below initializes an operator backed by the in-memory service, writes a file, reads it back, checks its metadata, and deletes it. It needs no credentials and no external service.  const std = @import(&quot;std&quot;); const opendal = @import(&quot;opendal&quot;); pub fn main() !void { // Initialize an operator for the &quot;memory&quot; backend with no options. var op = try opendal.Operator.init(&quot;memory&quot;, null); defer op.deinit(); // Write bytes to a path. try op.write(&quot;/hello.txt&quot;, &quot;Hello, World!&quot;); // Read them back. const data = try op.read(&quot;/hello.txt&quot;); std.debug.print(&quot;read: {s}
&quot;, .{data}); // Inspect metadata. var meta = try op.stat(&quot;/hello.txt&quot;); defer meta.deinit(); std.debug.print(&quot;size: {d} bytes
&quot;, .{meta.contentLength()}); std.debug.print(&quot;is file: {}
&quot;, .{meta.isFile()}); // Delete. try op.delete(&quot;/hello.txt&quot;); std.debug.print(&quot;done
&quot;, .{}); }   Operator.init takes the service scheme as a string and an optional pointer to anopendal_operator_options struct for service-specific configuration. Passing nulluses defaults.
